import React, { useState, useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { 
  X, Download, ZoomIn, ZoomOut, 
  ChevronLeft, ChevronRight, Calendar, MapPin, ArrowLeft, Globe
} from 'lucide-react';

// --- СҮЎРЕТЛЕРДИ ТОЛЫҚ ЭКРАНДА КӨРИЎ ҲӘМ ЖҮКЛЕП АЛЫЎ УШЫН КОМПОНЕНТ ---
const ImageLightbox = ({ images, currentIndex, isOpen, onClose, onNext, onPrev }) => {
  const [scale, setScale] = useState(1);

  useEffect(() => {
    if (!isOpen) setScale(1);
  }, [isOpen]);

  if (!isOpen) return null;

  const currentImage = images[currentIndex];

  const handleZoomIn = (e) => { e.stopPropagation(); setScale(prev => Math.min(prev + 0.5, 3)); };
  const handleZoomOut = (e) => { e.stopPropagation(); setScale(prev => Math.max(prev - 0.5, 1)); };
  
  const handleDownload = async (e) => {
    e.stopPropagation();
    try {
      const response = await fetch(currentImage);
      const blob = await response.blob();
      const url = window.URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `elena-archive-${currentIndex + 1}.jpg`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      window.URL.revokeObjectURL(url);
    } catch (error) {
      console.error("Сүўретти жүклеп алыўда қәте болды", error);
    }
  };

  return (
    <div className="fixed inset-0 z-[99999] flex items-center justify-center bg-black/95 backdrop-blur-md" onClick={onClose}>
      <div className="absolute top-0 left-0 right-0 p-4 flex justify-between items-center bg-gradient-to-b from-black/80 to-transparent z-50">
        <div className="text-white/70 text-sm font-medium">{currentIndex + 1} / {images.length}</div>
        <div className="flex items-center gap-4">
          <button onClick={handleZoomOut} className="text-white hover:text-blue-400 transition" title="Киширейтиў"><ZoomOut size={24} /></button>
          <button onClick={handleZoomIn} className="text-white hover:text-blue-400 transition" title="Үлкейтиў"><ZoomIn size={24} /></button>
          <button onClick={handleDownload} className="text-white hover:text-green-400 transition" title="Жүклеп алыў"><Download size={24} /></button>
          <button onClick={onClose} className="text-white hover:text-red-400 transition ml-4" title="Жабыў"><X size={32} /></button>
        </div>
      </div>
      <button onClick={(e) => { e.stopPropagation(); onPrev(); setScale(1); }} className="absolute left-4 top-1/2 -translate-y-1/2 p-3 bg-black/50 text-white rounded-full hover:bg-black/80 transition z-50"><ChevronLeft size={32} /></button>
      <button onClick={(e) => { e.stopPropagation(); onNext(); setScale(1); }} className="absolute right-4 top-1/2 -translate-y-1/2 p-3 bg-black/50 text-white rounded-full hover:bg-black/80 transition z-50"><ChevronRight size={32} /></button>
      <div className="w-full h-full flex items-center justify-center p-4 md:p-12 overflow-hidden" onClick={e => e.stopPropagation()}>
        <img src={currentImage} alt={`Архив сүўрети ${currentIndex + 1}`} className="max-w-full max-h-full object-contain transition-transform duration-300 ease-out" style={{ transform: `scale(${scale})` }} />
      </div>
    </div>
  );
};

// --- СҮЎРЕТЛЕР СЛАЙДЕРИ КОМПОНЕНТИ ---
const ImageSlider = ({ images, title }) => {
  const [lightboxOpen, setLightboxOpen] = useState(false);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isHovered, setIsHovered] = useState(false);
  const sliderRef = useRef(null);

  const openLightbox = (index) => { setCurrentIndex(index); setLightboxOpen(true); };
  const nextImage = () => setCurrentIndex((prev) => (prev === images.length - 1 ? 0 : prev + 1));
  const prevImage = () => setCurrentIndex((prev) => (prev === 0 ? images.length - 1 : prev - 1));

  useEffect(() => {
    let intervalId;
    if (!isHovered && !lightboxOpen) {
      intervalId = setInterval(() => {
        if (sliderRef.current) {
          const { scrollLeft, scrollWidth, clientWidth } = sliderRef.current;
          if (scrollLeft + clientWidth >= scrollWidth - 10) { sliderRef.current.scrollTo({ left: 0, behavior: 'smooth' }); } 
          else { sliderRef.current.scrollBy({ left: 320, behavior: 'smooth' }); }
        }
      }, 3000); 
    }
    return () => clearInterval(intervalId);
  }, [isHovered, lightboxOpen]);

  const scrollLeftManually = () => { if (sliderRef.current) sliderRef.current.scrollBy({ left: -320, behavior: 'smooth' }); };
  const scrollRightManually = () => { if (sliderRef.current) sliderRef.current.scrollBy({ left: 320, behavior: 'smooth' }); };

  return (
    <div className="my-10 bg-gray-50 dark:bg-[#121212] rounded-2xl p-4 border border-gray-200 dark:border-gray-800 shadow-xl transition-colors duration-300">
      {title && <h3 className="text-lg font-bold text-amber-600 dark:text-amber-500 mb-4 px-2 uppercase tracking-wide border-l-4 border-amber-500">{title}</h3>}
      <div className="relative group" onMouseEnter={() => setIsHovered(true)} onMouseLeave={() => setIsHovered(false)}>
        <button onClick={scrollLeftManually} className="absolute left-2 top-1/2 -translate-y-1/2 z-10 bg-black/60 hover:bg-black/90 text-white p-3 rounded-full opacity-70 hover:opacity-100 transition-all shadow-lg" title="Артқа жылжытыў"><ChevronLeft size={24} /></button>
        <div ref={sliderRef} className="flex overflow-x-auto gap-4 pb-4 snap-x snap-mandatory scrollbar-none" style={{ scrollbarWidth: 'none', msOverflowStyle: 'none' }}>
          {images.map((img, index) => (
            <div key={index} className="relative flex-none w-72 h-48 md:w-96 md:h-64 rounded-xl overflow-hidden cursor-pointer group/item snap-center shadow-md" onClick={() => openLightbox(index)}>
              <img src={img} alt={`Слайд ${index + 1}`} className="w-full h-full object-cover transition-transform duration-500 group-hover/item:scale-110" />
              <div className="absolute inset-0 bg-black/40 opacity-0 group-hover/item:opacity-100 transition-opacity flex items-center justify-center"><ZoomIn className="text-white" size={32} /></div>
            </div>
          ))}
        </div>
        <button onClick={scrollRightManually} className="absolute right-2 top-1/2 -translate-y-1/2 z-10 bg-black/60 hover:bg-black/90 text-white p-3 rounded-full opacity-70 hover:opacity-100 transition-all shadow-lg" title="Алдыға жылжытыў"><ChevronRight size={24} /></button>
      </div>
      <ImageLightbox images={images} currentIndex={currentIndex} isOpen={lightboxOpen} onClose={() => setLightboxOpen(false)} onNext={nextImage} onPrev={prevImage} />
    </div>
  );
};


